function urlencoded (options) {
  const normalizedOptions = normalizeOptions(options, 'application/x-www-form-urlencoded')

  if (normalizedOptions.defaultCharset !== 'utf-8' && normalizedOptions.defaultCharset !== 'iso-8859-1') {
    throw new TypeError('option defaultCharset must be either utf-8 or iso-8859-1')
  }

  // create the appropriate query parser
  const parse = createQueryParser(options)

  const readOptions = {
    ...normalizedOptions,
    // assert charset
    isValidCharset: (charset) => charset === 'utf-8' || charset === 'iso-8859-1'
  }

  return function urlencodedParser (req, res, next) {
    read(req, res, next, parse, debug, readOptions)
  }
}

morgan.format('dev', function developmentFormatLine (tokens, req, res) {
  // get the status code if response written
  var status = headersSent(res)
    ? res.statusCode
    : undefined

  // get status color
  var color = status >= 500 ? 31 // red
    : status >= 400 ? 33 // yellow
      : status >= 300 ? 36 // cyan
        : status >= 200 ? 32 // green
          : 0 // no color

  // get colored function
  var fn = developmentFormatLine[color]

  if (!fn) {
    // compile
    fn = developmentFormatLine[color] = compile('\x1b[0m:method :url \x1b[' +
      color + 'm:status\x1b[0m :response-time ms - :res[content-length]\x1b[0m')
  }

  return fn(tokens, req, res)
})

export function createCookieAuthRefreshMiddleware(options: {
  auth: AuthService;
  httpAuth: HttpAuthService;
}) {
  const { auth, httpAuth } = options;
  const router = Router();

  // Endpoint that sets the cookie for the user
  router.get(WELL_KNOWN_COOKIE_PATH_V1, async (_, res) => {
    const { expiresAt } = await httpAuth.issueUserCookie(res);
    res.json({ expiresAt: expiresAt.toISOString() });
  });

  // Endpoint that removes the cookie for the user
  router.delete(WELL_KNOWN_COOKIE_PATH_V1, async (_, res) => {
    const credentials = await auth.getNoneCredentials();
    await httpAuth.issueUserCookie(res, { credentials });
    res.status(204).end();
  });

  return router;
}

constructor(
  container: interfaces.Container,
  customRouter?: Router | null,
  routingConfig?: RoutingConfig | null,
  customApp?: Application | null,
  authProvider?: (new () => AuthProvider) | null,
  forceControllers: boolean = true,
) {
  this._container = container;
  this._forceControllers = forceControllers;
  this._router = customRouter || Router();
  this._routingConfig = routingConfig || {
    rootPath: DEFAULT_ROUTING_ROOT_PATH,
  };
  this._app = customApp || express();
  if (authProvider) {
    this._authProvider = authProvider;
    container.bind<AuthProvider>(TYPE.AuthProvider).to(this._authProvider);
  }
}

function acceptParams (str) {
  var length = str.length;
  var colonIndex = str.indexOf(';');
  var index = colonIndex === -1 ? length : colonIndex;
  var ret = { value: str.slice(0, index).trim(), quality: 1, params: {} };

  while (index < length) {
    var splitIndex = str.indexOf('=', index);
    if (splitIndex === -1) break;

    var colonIndex = str.indexOf(';', index);
    var endIndex = colonIndex === -1 ? length : colonIndex;

    if (splitIndex > endIndex) {
      index = str.lastIndexOf(';', splitIndex - 1) + 1;
      continue;
    }

    var key = str.slice(index, splitIndex).trim();
    var value = str.slice(splitIndex + 1, endIndex).trim();

    if (key === 'q') {
      ret.quality = parseFloat(value);
    } else {
      ret.params[key] = value;
    }

    index = endIndex + 1;
  }

  return ret;
}

function createCustomFetch(config) {
  const fetchFn = config.customFetch || fetch;
  return async (fetchUrl, options) => {
    const headers = new Headers(options.headers);

    // Add User-Agent header
    headers.set(
      'User-Agent',
      config.httpUserAgent || `${pkg.name}/${pkg.version}`,
    );

    // Add telemetry header if enabled
    if (config.enableTelemetry) {
      headers.set(
        'Auth0-Client',
        Buffer.from(JSON.stringify(telemetryHeader)).toString('base64'),
      );
    }

    return fetchFn(fetchUrl, {
      ...options,
      headers,
    });
  };
}

function setup () {
  var fileFilter = this.fileFilter
  var filesLeft = Object.create(null)

  fields.forEach(function (field) {
    if (typeof field.maxCount === 'number') {
      filesLeft[field.name] = field.maxCount
    } else {
      filesLeft[field.name] = Infinity
    }
  })

  function wrappedFileFilter (req, file, cb) {
    if ((filesLeft[file.fieldname] || 0) <= 0) {
      return cb(new MulterError('LIMIT_UNEXPECTED_FILE', file.fieldname))
    }

    filesLeft[file.fieldname] -= 1
    fileFilter(req, file, cb)
  }

  return {
    limits: this.limits,
    preservePath: this.preservePath,
    defParamCharset: this.defParamCharset,
    storage: this.storage,
    fileFilter: wrappedFileFilter,
    fileStrategy: fileStrategy
  }
}

private async _getCurrentUser(
  req: Request,
  res: Response,
  next: NextFunction,
): Promise<Principal> {
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  if (this._authProvider !== undefined) {
    const authProvider: AuthProvider = this._container.get<AuthProvider>(
      TYPE.AuthProvider,
    );
    return authProvider.getUser(req, res, next);
  }
  return Promise.resolve<Principal>({
    details: null,
    isAuthenticated: async (): Promise<boolean> => false,
    isInRole: async (_role: string): Promise<boolean> => false,
    isResourceOwner: async (_resourceId: unknown): Promise<boolean> => false,
  });
}

function getLogMeta(req: Request, res: Response): LogMeta {
  const referrer = req.headers.referer ?? req.headers.referrer;
  const userAgent = req.headers['user-agent'];
  const contentLength = Number(res.getHeader('content-length'));

  const meta: LogMeta = {
    date: new Date().toISOString(),
    method: req.method,
    url: req.originalUrl ?? req.url,
    status: res.statusCode,
    httpVersion: `${req.httpVersionMajor}.${req.httpVersionMinor}`,
  };

  if (userAgent) {
    meta.userAgent = userAgent;
  }

  if (isFinite(contentLength)) {
    meta.contentLength = contentLength;
  }

  if (referrer) {
    meta.referrer = Array.isArray(referrer) ? referrer.join(', ') : referrer;
  }

  return meta;
}

rateLimit(): RequestHandler {
  const enabled = this.#config.has('backend.rateLimit');
  if (!enabled) {
    return (_req: Request, _res: Response, next: NextFunction) => {
      next();
    };
  }

  const useDefaults = this.#config.getOptional('backend.rateLimit') === true;
  const rateLimitOptions = useDefaults
    ? undefined
    : this.#config.getOptionalConfig('backend.rateLimit');

  // Global rate limiting disabled
  if (
    rateLimitOptions &&
    rateLimitOptions.getOptionalBoolean('global') === false
  ) {
    return (_req: Request, _res: Response, next: NextFunction) => {
      next();
    };
  }

  return rateLimitMiddleware({
    store: useDefaults
      ? undefined
      : RateLimitStoreFactory.create({ config: this.#config }),
    config: rateLimitOptions,
  });
}

async function importPrivateKey(keyData, alg) {
  // CryptoKey: algorithm already embedded, pass through
  if (
    typeof keyData?.algorithm?.name === 'string' &&
    Array.isArray(keyData?.usages)
  ) {
    return keyData;
  }

  // Node.js KeyObject: export to PKCS8 PEM then import as CryptoKey
  if (keyData?.asymmetricKeyType) {
    const pem = await exportPKCS8(keyData);
    return importPKCS8(pem, alg);
  }

  // Plain object that is not a Buffer: treat as JWK
  if (typeof keyData === 'object' && !Buffer.isBuffer(keyData)) {
    return importJWK(keyData, alg);
  }

  // PEM string or Buffer
  return importPKCS8(keyData.toString(), alg);
}

function getHeaderValueFromOptions({
  policy = ["no-referrer"],
}: Readonly<ReferrerPolicyOptions>): string {
  const tokens = typeof policy === "string" ? [policy] : policy;

  if (tokens.length === 0) {
    throw new Error("Referrer-Policy received no policy tokens");
  }

  const tokensSeen = new Set<ReferrerPolicyToken>();
  tokens.forEach((token) => {
    if (!ALLOWED_TOKENS.has(token)) {
      throw new Error(
        `Referrer-Policy received an unexpected policy token ${JSON.stringify(
          token,
        )}`,
      );
    } else if (tokensSeen.has(token)) {
      throw new Error(
        `Referrer-Policy received a duplicate policy token ${JSON.stringify(
          token,
        )}`,
      );
    }
    tokensSeen.add(token);
  });

  return tokens.join(",");
}

const assertDirectiveValueEntryIsValid = (
  directiveName: string,
  directiveValueEntry: string,
): void => {
  if (
    SHOULD_BE_QUOTED.has(directiveValueEntry) ||
    directiveValueEntry.startsWith("nonce-") ||
    directiveValueEntry.startsWith("sha256-") ||
    directiveValueEntry.startsWith("sha384-") ||
    directiveValueEntry.startsWith("sha512-")
  ) {
    throw new Error(
      `Content-Security-Policy received an invalid directive value for ${JSON.stringify(
        directiveName,
      )}. ${JSON.stringify(directiveValueEntry)} should be quoted`,
    );
  }
};

private extractRequestBodySchemaNodes(
  node: Root<OpenAPIV3.OperationObject>,
): Root<SchemaObject>[] {
  const op = node.schema;
  const bodySchema = this.resolveSchema<OpenAPIV3.RequestBodyObject>(
    op.requestBody,
  );
  op.requestBody = bodySchema;

  if (!bodySchema?.content) return [];

  const result: Root<SchemaObject>[] = [];
  const contentEntries = Object.entries(bodySchema.content);
  for (const [type, mediaTypeObject] of contentEntries) {
    const mediaTypeSchema = this.resolveSchema<SchemaObject>(
      mediaTypeObject.schema,
    );
    op.requestBody.content[type].schema = mediaTypeSchema;

    // TODO replace with visitor
    this.removeExamples(op.requestBody.content[type]);

    const path = [...node.path, 'requestBody', 'content', type, 'schema'];
    result.push(new Root(mediaTypeSchema, path));
  }
  return result;
}

const setDraft8Headers = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
	name: string,
	key: string,
): void => {
	if (response.headersSent) return

	const windowSeconds = Math.ceil(windowMs / 1000)
	const resetSeconds = getResetSeconds(windowMs, info.resetTime)
	const partitionKey = getPartitionKey(key)

	const header = `r=${info.remaining}; t=${resetSeconds}`
	const policy = `q=${info.limit}; w=${windowSeconds}; pk=:${partitionKey}:`

	response.append('RateLimit', `"${name}"; ${header}`)
	response.append('RateLimit-Policy', `"${name}"; ${policy}`)
}

() => {
  // Try to use Joi.binary() if available (Node.js)
  if (typeof Joi.binary === 'function') {
    try {
      return Joi.binary().min(8);
    } catch {
      // Fall through to custom validator
    }
  }
  // Fallback for environments where Joi.binary() is not available
  return Joi.any()
    .custom((value, helpers) => {
      const isBufferLike =
        (typeof Buffer !== 'undefined' && Buffer.isBuffer(value)) ||
        value instanceof Uint8Array;

      if (!isBufferLike) {
        return helpers.error('binary.base');
      }
      if (value.length < 8) {
        return helpers.error('binary.min', { limit: 8 });
      }
      return value;
    })
    .messages({
      'binary.base': '{{#label}} must be a buffer',
      'binary.min': '{{#label}} must be at least {{#limit}} bytes',
    });
}
